mapper.select:
select * from ygt_member_join_source
where ygt_mjs_customer_user_id = #{customerUserId}
and ygt_mjs_source_share_code = #{shareCode}
limit 1

select * from ygt_member_join_source

    and ygt_mjs_source_campaign_id = #{campaignId}
    and ygt_mjs_source_wecom_group_id = #{wecomGroupId}
    and ygt_mjs_customer_user_id = #{customerUserId}
    and ygt_mjs_bind_status = #{bindStatus}

order by ygt_member_join_source_id desc
limit #{offset}, #{limit}

select count(*) from ygt_member_join_source

    and ygt_mjs_source_campaign_id = #{campaignId}
    and ygt_mjs_source_wecom_group_id = #{wecomGroupId}
    and ygt_mjs_customer_user_id = #{customerUserId}
    and ygt_mjs_bind_status = #{bindStatus}

mapper.update:
update ygt_member_join_source
ygt_mjs_open_id = #{ygtMjsOpenId}, ygt_mjs_union_id = #{ygtMjsUnionId}, ygt_mjs_wecom_external_user_id = #{ygtMjsWecomExternalUserId}, ygt_mjs_wecom_user_id = #{ygtMjsWecomUserId}, ygt_mjs_phone_snapshot = #{ygtMjsPhoneSnapshot}, ygt_mjs_nickname_snapshot = #{ygtMjsNicknameSnapshot}, ygt_mjs_bind_status = #{ygtMjsBindStatus}, ygt_mjs_match_method = #{ygtMjsMatchMethod}, ygt_mjs_update_time = now()
where ygt_member_join_source_id = #{ygtMemberJoinSourceId}
